module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const invert = String(args.invert) === 'true';
const stats = sections.map((s) => (s || '').trim()).filter(Boolean);
let html = `\n\n<div class="mdp-mod-statdelta">`;
stats.forEach((st) => {
  const [value = '', label = '', change = ''] = st.split('\n').map((x) => x.trim());
  const up = /^\+/.test(change) || (/^[^-]/.test(change) && /↑|▲/.test(change));
  const down = /^-/.test(change) || /↓|▼/.test(change);
  const good = invert ? down : up;
  const dir = up ? '▲' : down ? '▼' : '';
  const cls = change ? (good ? ' is-good' : ' is-bad') : '';
  html += `<div class="mdp-sd-item"><div class="mdp-sd-value">${esc(value)}</div><div class="mdp-sd-label">${esc(label)}</div>` +
    (change ? `<div class="mdp-sd-change${cls}">${dir} ${esc(change.replace(/^[+\-]/, ''))}</div>` : '') + `</div>`;
});
html += `</div>\n\n`;
return html;
